     1|/**
     2| * IVX AI Engineering Command Center — Owner-only dashboard.
     3| *
     4| * Displays all 12 AI agents with seniority scores, assigned developer roles,
     5| * task ledger, ownership rules, and drill-down capability details.
     6| */
     7|import React, { useCallback, useMemo, useState } from 'react';
     8|import {
     9|  View,
    10|  Text,
    11|  ScrollView,
    12|  Pressable,
    13|  RefreshControl,
    14|  Modal,
    15|  StyleSheet,
    16|  ActivityIndicator,
    17|  FlatList,
    18|  Linking,
    19|} from 'react-native';
    20|import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
    21|import { router } from 'expo-router';
    22|import {
    23|  getAgentAuditOverview,
    24|  createTaskLedgerEntry,
    25|  type AgentAuditResult,
    26|  type AgentAuditOverview,
    27|  type CapabilityScore,
    28|  type SeniorityLevel,
    29|  type TaskLedgerEntry,
    30|} from '@/src/modules/ivx-owner-ai/services/ivxAgentAuditService';
    31|import Colors from '@/constants/colors';
    32|
    33|const GOLD = '#FFD700';
    34|const GREEN = '#00C48C';
    35|const RED = '#FF4D4D';
    36|const BLUE = '#4A90D9';
    37|const DARK_BG = '#0A0A0F';
    38|const CARD_BG = '#15151F';
    39|const CARD_BORDER = '#252535';
    40|
    41|const SENIORITY_COLORS: Record<SeniorityLevel, string> = {
    42|  SENIOR: GREEN,
    43|  MID: GOLD,
    44|  JUNIOR: BLUE,
    45|  NOT_A_DEVELOPER: RED,
    46|};
    47|
    48|const SCORE_COLORS: Record<CapabilityScore, string> = {
    49|  PASS: GREEN,
    50|  PARTIAL: GOLD,
    51|  FAIL: RED,
    52|  NOT_CONFIGURED: '#666',
    53|};
    54|
    55|const STATUS_COLORS: Record<string, string> = {
    56|  NOT_STARTED: '#666',
    57|  ANALYZING: BLUE,
    58|  IN_PROGRESS: GOLD,
    59|  CODE_COMPLETE: BLUE,
    60|  REVIEW_REQUIRED: GOLD,
    61|  TEST_FAILED: RED,
    62|  TEST_PASSED: GREEN,
    63|  DEPLOYMENT_FAILED: RED,
    64|  DEPLOYED: BLUE,
    65|  PRODUCTION_VERIFIED: GREEN,
    66|  BLOCKED: RED,
    67|  REJECTED: RED,
    68|};
    69|
    70|type AgentFilter = 'all' | SeniorityLevel;
    71|type LedgerFilter = 'all' | 'completed' | 'failed' | 'blocked' | 'deployed' | 'verified';
    72|
    73|export default function AgentCommandCenterScreen() {
    74|  const queryClient = useQueryClient();
    75|  const [agentFilter, setAgentFilter] = useState<AgentFilter>('all');
    76|  const [ledgerFilter, setLedgerFilter] = useState<LedgerFilter>('all');
    77|  const [selectedAgent, setSelectedAgent] = useState<AgentAuditResult | null>(null);
    78|  const [showLedger, setShowLedger] = useState(false);
    79|
    80|  const auditQuery = useQuery<AgentAuditOverview>({
    81|    queryKey: ['ivx-agent-audit', 'overview'],
    82|    queryFn: getAgentAuditOverview,
    83|  });
    84|
    85|  const onRefresh = useCallback(() => {
    86|    void auditQuery.refetch();
    87|  }, [auditQuery]);
    88|
    89|  const createTaskMutation = useMutation({
    90|    mutationFn: (input: { title: string; module: string; assignedAI: number; reviewingAI: number; priority: 'critical' | 'high' | 'medium' | 'low' }) =>
    91|      createTaskLedgerEntry(input),
    92|    onSuccess: () => {
    93|      void queryClient.invalidateQueries({ queryKey: ['ivx-agent-audit', 'overview'] });
    94|    },
    95|  });
    96|
    97|  const data = auditQuery.data;
    98|  const summary = data?.summary;
    99|  const agents = data?.agents ?? [];
   100|  const ledger = data?.taskLedger ?? [];
   101|
   102|  const filteredAgents = useMemo(() => {
   103|    if (agentFilter === 'all') return agents;
   104|    return agents.filter((a) => a.seniority === agentFilter);
   105|  }, [agents, agentFilter]);
   106|
   107|  const filteredLedger = useMemo(() => {
   108|    if (ledgerFilter === 'all') return ledger;
   109|    if (ledgerFilter === 'completed') return ledger.filter((t) => t.status === 'PRODUCTION_VERIFIED');
   110|    if (ledgerFilter === 'failed') return ledger.filter((t) => t.status === 'TEST_FAILED' || t.status === 'DEPLOYMENT_FAILED' || t.status === 'REJECTED');
   111|    if (ledgerFilter === 'blocked') return ledger.filter((t) => t.status === 'BLOCKED');
   112|    if (ledgerFilter === 'deployed') return ledger.filter((t) => t.status === 'DEPLOYED' || t.status === 'PRODUCTION_VERIFIED');
   113|    if (ledgerFilter === 'verified') return ledger.filter((t) => t.status === 'PRODUCTION_VERIFIED');
   114|    return ledger;
   115|  }, [ledger, ledgerFilter]);
   116|
   117|  if (auditQuery.isLoading && !data) {
   118|    return (
   119|      <View style={styles.loadingContainer}>
   120|        <ActivityIndicator size="large" color={GOLD} />
   121|        <Text style={styles.loadingText}>Loading AI Engineering Command Center…</Text>
   122|      </View>
   123|    );
   124|  }
   125|
   126|  if (auditQuery.error && !data) {
   127|    return (
   128|      <View style={styles.loadingContainer}>
   129|        <Text style={styles.errorTitle}>Failed to load command center</Text>
   130|        <Text style={styles.errorBody}>
   131|          {auditQuery.error instanceof Error ? auditQuery.error.message : 'Unknown error'}
   132|        </Text>
   133|        <Pressable style={styles.retryBtn} onPress={onRefresh}>
   134|          <Text style={styles.retryBtnText}>Retry</Text>
   135|        </Pressable>
   136|      </View>
   137|    );
   138|  }
   139|
   140|  return (
   141|    <ScrollView
   142|      style={styles.container}
   143|      refreshControl={<RefreshControl tintColor={GOLD} refreshing={auditQuery.isFetching} onRefresh={onRefresh} />}
   144|      testID="agent-command-center-scroll"
   145|    >
   146|      {/* Header */}
   147|      <View style={styles.header}>
   148|        <Pressable onPress={() => router.back()} testID="command-center-back">
   149|          <Text style={styles.backBtn}>← Back</Text>
   150|        </Pressable>
   151|        <Text style={styles.headerTitle}>IVX AI Engineering</Text>
   152|        <Text style={styles.headerSubtitle}>Command Center</Text>
   153|      </View>
   154|
   155|      {/* Executive Summary */}
   156|      {summary && (
   157|        <View style={styles.summaryCard} testID="command-center-summary">
   158|          <View style={styles.summaryRow}>
   159|            <View style={styles.summaryTile}>
   160|              <Text style={[styles.summaryValue, { color: GREEN }]}>{summary.seniorCount}</Text>
   161|              <Text style={styles.summaryLabel}>Senior</Text>
   162|            </View>
   163|            <View style={styles.summaryTile}>
   164|              <Text style={[styles.summaryValue, { color: GOLD }]}>{summary.midCount}</Text>
   165|              <Text style={styles.summaryLabel}>Mid-level</Text>
   166|            </View>
   167|            <View style={styles.summaryTile}>
   168|              <Text style={[styles.summaryValue, { color: BLUE }]}>{summary.juniorCount}</Text>
   169|              <Text style={styles.summaryLabel}>Junior</Text>
   170|            </View>
   171|            <View style={styles.summaryTile}>
   172|              <Text style={[styles.summaryValue, { color: RED }]}>{summary.notDeveloperCount}</Text>
   173|              <Text style={styles.summaryLabel}>Non-dev</Text>
   174|            </View>
   175|          </View>
   176|          <View style={styles.summaryRow}>
   177|            <View style={styles.summaryTile}>
   178|              <Text style={styles.summaryValueSmall}>{summary.withRepoExecution}</Text>
   179|              <Text style={styles.summaryLabel}>Code exec</Text>
   180|            </View>
   181|            <View style={styles.summaryTile}>
   182|              <Text style={styles.summaryValueSmall}>{summary.withDeploymentCapability}</Text>
   183|              <Text style={styles.summaryLabel}>Deploy</Text>
   184|            </View>
   185|            <View style={styles.summaryTile}>
   186|              <Text style={styles.summaryValueSmall}>{summary.withProductionEvidence}</Text>
   187|              <Text style={styles.summaryLabel}>Evidence</Text>
   188|            </View>
   189|            <View style={styles.summaryTile}>
   190|              <Text style={styles.summaryValueSmall}>{summary.totalAgents}</Text>
   191|              <Text style={styles.summaryLabel}>Total</Text>
   192|            </View>
   193|          </View>
   194|          {summary.criticalGaps.length > 0 && (
   195|            <View style={styles.gapsContainer}>
   196|              <Text style={styles.gapsTitle}>Critical Gaps</Text>
   197|              {summary.criticalGaps.map((gap, i) => (
   198|                <Text key={i} style={styles.gapItem}>• {gap}</Text>
   199|              ))}
   200|            </View>
   201|          )}
   202|        </View>
   203|      )}
   204|
   205|      {/* Agent Filter */}
   206|      <View style={styles.filterRow}>
   207|        {(['all', 'SENIOR', 'MID', 'JUNIOR', 'NOT_A_DEVELOPER'] as AgentFilter[]).map((f) => (
   208|          <Pressable
   209|            key={f}
   210|            style={[styles.filterChip, agentFilter === f && styles.filterChipActive]}
   211|            onPress={() => setAgentFilter(f)}
   212|          >
   213|            <Text style={[styles.filterText, agentFilter === f && styles.filterTextActive]}>
   214|              {f === 'all' ? 'All' : f === 'NOT_A_DEVELOPER' ? 'Non-dev' : f.charAt(0) + f.slice(1).toLowerCase()}
   215|            </Text>
   216|          </Pressable>
   217|        ))}
   218|      </View>
   219|
   220|      {/* Agent Cards */}
   221|      <View style={styles.agentsContainer} testID="command-center-agents">
   222|        {filteredAgents.map((agent) => (
   223|          <Pressable
   224|            key={agent.executiveAgentId}
   225|            style={styles.agentCard}
   226|            onPress={() => setSelectedAgent(agent)}
   227|            testID={`agent-audit-card-${agent.agentNumber}`}
   228|          >
   229|            <View style={styles.agentCardHeader}>
   230|              <View style={styles.agentNumberBadge}>
   231|                <Text style={styles.agentNumberText}>AI {agent.agentNumber}</Text>
   232|              </View>
   233|              <View style={[styles.seniorityBadge, { backgroundColor: SENIORITY_COLORS[agent.seniority] + '20', borderColor: SENIORITY_COLORS[agent.seniority] }]}>
   234|                <Text style={[styles.seniorityText, { color: SENIORITY_COLORS[agent.seniority] }]}>
   235|                  {agent.seniority.replace(/_/g, ' ')}
   236|                </Text>
   237|              </View>
   238|            </View>
   239|            <Text style={styles.agentName}>{agent.currentName}</Text>
   240|            <Text style={styles.agentRole}>{agent.assignedRoleTitle}</Text>
   241|            <View style={styles.scoreBar}>
   242|              <View style={[styles.scoreBarFill, { width: `${agent.scorePercentage}%`, backgroundColor: SENIORITY_COLORS[agent.seniority] }]} />
   243|            </View>
   244|            <Text style={styles.scoreText}>{agent.scorePercentage}% senior developer score</Text>
   245|            <Text style={styles.agentGap} numberOfLines={2}>{agent.mainGap}</Text>
   246|            <View style={styles.agentMetaRow}>
   247|              <Text style={styles.agentMeta}>Tools: {agent.allowedTools.length}</Text>
   248|              <Text style={styles.agentMeta}>Risk: {agent.riskLevel}</Text>
   249|              <Text style={styles.agentMeta}>{agent.canExecuteCode ? 'Can code' : 'Analysis only'}</Text>
   250|            </View>
   251|          </Pressable>
   252|        ))}
   253|      </View>
   254|
   255|      {/* Task Ledger Toggle */}
   256|      <Pressable
   257|        style={styles.ledgerToggle}
   258|        onPress={() => setShowLedger(!showLedger)}
   259|        testID="command-center-ledger-toggle"
   260|      >
   261|        <Text style={styles.ledgerToggleText}>
   262|          {showLedger ? '▼' : '▶'} Task Ledger ({ledger.length})
   263|        </Text>
   264|      </Pressable>
   265|
   266|      {showLedger && (
   267|        <View style={styles.ledgerContainer} testID="command-center-ledger">
   268|          <View style={styles.ledgerFilterRow}>
   269|            {(['all', 'completed', 'failed', 'blocked', 'deployed', 'verified'] as LedgerFilter[]).map((f) => (
   270|              <Pressable
   271|                key={f}
   272|                style={[styles.filterChip, ledgerFilter === f && styles.filterChipActive]}
   273|                onPress={() => setLedgerFilter(f)}
   274|              >
   275|                <Text style={[styles.filterText, ledgerFilter === f && styles.filterTextActive]}>
   276|                  {f.charAt(0).toUpperCase() + f.slice(1)}
   277|                </Text>
   278|              </Pressable>
   279|            ))}
   280|          </View>
   281|          {filteredLedger.length === 0 ? (
   282|            <Text style={styles.emptyText}>No tasks in ledger. Tasks appear here as agents are assigned work.</Text>
   283|          ) : (
   284|            filteredLedger.map((task) => <TaskLedgerRow key={task.taskId} task={task} />)
   285|          )}
   286|        </View>
   287|      )}
   288|
   289|      {/* Ownership Rules */}
   290|      {data && (
   291|        <View style={styles.rulesContainer} testID="command-center-rules">
   292|          <Text style={styles.rulesTitle}>Ownership Rules</Text>
   293|          {data.ownershipRules.map((rule, i) => (
   294|            <Text key={i} style={styles.ruleItem}>{i + 1}. {rule}</Text>
   295|          ))}
   296|        </View>
   297|      )}
   298|
   299|      <View style={styles.footer}>
   300|        <Text style={styles.footerText}>
   301|          Marker: {data?.marker ?? 'N/A'} · Generated: {data?.generatedAt ? new Date(data.generatedAt).toUTCString() : 'N/A'}
   302|        </Text>
   303|      </View>
   304|
   305|      {/* Agent Detail Modal */}
   306|      <Modal
   307|        visible={selectedAgent !== null}
   308|        animationType="slide"
   309|        transparent={true}
   310|        onRequestClose={() => setSelectedAgent(null)}
   311|      >
   312|        <View style={styles.modalOverlay}>
   313|          <View style={styles.modalContent}>
   314|            {selectedAgent && (
   315|              <ScrollView testID="agent-detail-modal">
   316|                <View style={styles.modalHeader}>
   317|                  <Text style={styles.modalTitle}>AI {selectedAgent.agentNumber}: {selectedAgent.currentName}</Text>
   318|                  <Pressable onPress={() => setSelectedAgent(null)} testID="agent-detail-close">
   319|                    <Text style={styles.modalCloseBtn}>✕</Text>
   320|                  </Pressable>
   321|                </View>
   322|
   323|                <Text style={styles.modalSection}>Assigned Role</Text>
   324|                <Text style={styles.modalRoleText}>{selectedAgent.assignedRoleTitle}</Text>
   325|
   326|                <Text style={styles.modalSection}>Current Engine</Text>
   327|                <Text style={styles.modalMetaText}>{selectedAgent.currentEngine}</Text>
   328|
   329|                <Text style={styles.modalSection}>Framework Agent</Text>
   330|                <Text style={styles.modalMetaText}>{selectedAgent.frameworkAgentId} (risk: {selectedAgent.riskLevel})</Text>
   331|
   332|                <Text style={styles.modalSection}>Allowed Tools</Text>
   333|                <Text style={styles.modalMetaText}>{selectedAgent.allowedTools.join(', ') || 'none'}</Text>
   334|
   335|                <Text style={styles.modalSection}>Files Owned</Text>
   336|                {selectedAgent.filesOwned.map((f, i) => (
   337|                  <Text key={i} style={styles.modalFileText}>• {f}</Text>
   338|                ))}
   339|
   340|                <Text style={styles.modalSection}>Current Blocker</Text>
   341|                <Text style={[styles.modalMetaText, { color: RED }]}>{selectedAgent.currentBlocker}</Text>
   342|
   343|                <Text style={styles.modalSection}>Main Gap</Text>
   344|                <Text style={[styles.modalMetaText, { color: GOLD }]}>{selectedAgent.mainGap}</Text>
   345|
   346|                <Text style={styles.modalSection}>20-Capability Scorecard</Text>
   347|                <Text style={styles.modalScoreText}>Overall: {selectedAgent.scorePercentage}% · {selectedAgent.seniority.replace(/_/g, ' ')}</Text>
   348|
   349|                {selectedAgent.capabilities.map((cap, i) => (
   350|                  <View key={i} style={styles.capabilityRow}>
   351|                    <View style={[styles.capabilityDot, { backgroundColor: SCORE_COLORS[cap.score] }]} />
   352|                    <View style={styles.capabilityContent}>
   353|                      <Text style={styles.capabilityName}>{i + 1}. {cap.capability}</Text>
   354|                      <Text style={[styles.capabilityScore, { color: SCORE_COLORS[cap.score] }]}>
   355|                        {cap.score}
   356|                      </Text>
   357|                      <Text style={styles.capabilityEvidence}>{cap.evidence}</Text>
   358|                    </View>
   359|                  </View>
   360|                ))}
   361|              </ScrollView>
   362|            )}
   363|          </View>
   364|        </View>
   365|      </Modal>
   366|    </ScrollView>
   367|  );
   368|}
   369|
   370|function TaskLedgerRow({ task }: { task: TaskLedgerEntry }) {
   371|  const [expanded, setExpanded] = useState(false);
   372|  const statusColor = STATUS_COLORS[task.status] ?? '#666';
   373|
   374|  return (
   375|    <Pressable
   376|      style={styles.ledgerRow}
   377|      onPress={() => setExpanded(!expanded)}
   378|      testID={`ledger-row-${task.taskId}`}
   379|    >
   380|      <View style={styles.ledgerHeader}>
   381|        <View style={[styles.ledgerStatusDot, { backgroundColor: statusColor }]} />
   382|        <Text style={styles.ledgerTitle} numberOfLines={1}>{task.title || task.taskId}</Text>
   383|        <Text style={[styles.ledgerStatus, { color: statusColor }]}>{task.status.replace(/_/g, ' ')}</Text>
   384|      </View>
   385|      <Text style={styles.ledgerMeta}>
   386|        AI {task.assignedAI} → Review AI {task.reviewingAI} · {task.priority} · {task.module}
   387|      </Text>
   388|      {expanded && (
   389|        <View style={styles.ledgerDetail}>
   390|          {task.startTime && <Text style={styles.ledgerDetailText}>Start: {task.startTime}</Text>}
   391|          {task.lastActivityTime && <Text style={styles.ledgerDetailText}>Last activity: {task.lastActivityTime}</Text>}
   392|          {task.commitSha && <Text style={styles.ledgerDetailText}>Commit: {task.commitSha.slice(0, 12)}</Text>}
   393|          {task.deploymentId && <Text style={styles.ledgerDetailText}>Deploy ID: {task.deploymentId}</Text>}
   394|          {task.testCommand && <Text style={styles.ledgerDetailText}>Test: {task.testCommand}</Text>}
   395|          {task.testResult && <Text style={styles.ledgerDetailText}>Test result: {task.testResult}</Text>}
   396|          {task.productionUrl && <Text style={styles.ledgerDetailText}>URL: {task.productionUrl}</Text>}
   397|          {task.blocker && <Text style={[styles.ledgerDetailText, { color: RED }]}>Blocker: {task.blocker}</Text>}
   398|          {task.verificationEvidence && <Text style={[styles.ledgerDetailText, { color: GREEN }]}>Evidence: {task.verificationEvidence}</Text>}
   399|          {task.filesChanged.length > 0 && (
   400|            <View>
   401|              <Text style={styles.ledgerDetailText}>Files changed:</Text>
   402|              {task.filesChanged.map((f, i) => <Text key={i} style={styles.ledgerFile}>  • {f}</Text>)}
   403|            </View>
   404|          )}
   405|        </View>
   406|      )}
   407|    </Pressable>
   408|  );
   409|}
   410|
   411|const styles = StyleSheet.create({
   412|  container: { flex: 1, backgroundColor: DARK_BG },
   413|  loadingContainer: { flex: 1, backgroundColor: DARK_BG, justifyContent: 'center', alignItems: 'center', padding: 24 },
   414|  loadingText: { color: GOLD, fontSize: 16, marginTop: 12, fontWeight: '600' as const },
   415|  errorTitle: { color: RED, fontSize: 18, fontWeight: '700' as const, marginBottom: 8 },
   416|  errorBody: { color: '#999', fontSize: 14, textAlign: 'center', marginBottom: 16 },
   417|  retryBtn: { backgroundColor: GOLD, paddingHorizontal: 24, paddingVertical: 12, borderRadius: 8 },
   418|  retryBtnText: { color: DARK_BG, fontWeight: '700' as const, fontSize: 14 },
   419|  header: { padding: 20, paddingTop: 60, backgroundColor: CARD_BG, borderBottomWidth: 1, borderBottomColor: CARD_BORDER },
   420|  backBtn: { color: GOLD, fontSize: 16, fontWeight: '600' as const, marginBottom: 8 },
   421|  headerTitle: { color: GOLD, fontSize: 24, fontWeight: '800' as const },
   422|  headerSubtitle: { color: '#FFF', fontSize: 16, fontWeight: '500' as const, marginTop: 2 },
   423|  summaryCard: { backgroundColor: CARD_BG, margin: 12, borderRadius: 12, padding: 16, borderWidth: 1, borderColor: CARD_BORDER },
   424|  summaryRow: { flexDirection: 'row', justifyContent: 'space-around', marginBottom: 12 },
   425|  summaryTile: { alignItems: 'center' },
   426|  summaryValue: { fontSize: 28, fontWeight: '800' as const },
   427|  summaryValueSmall: { fontSize: 20, fontWeight: '700' as const, color: '#FFF' },
   428|  summaryLabel: { fontSize: 11, color: '#888', marginTop: 4 },
   429|  gapsContainer: { marginTop: 8, paddingTop: 12, borderTopWidth: 1, borderTopColor: CARD_BORDER },
   430|  gapsTitle: { color: RED, fontSize: 14, fontWeight: '700' as const, marginBottom: 6 },
   431|  gapItem: { color: '#CCC', fontSize: 12, marginBottom: 4 },
   432|  filterRow: { flexDirection: 'row', flexWrap: 'wrap', paddingHorizontal: 12, gap: 6, marginBottom: 8 },
   433|  filterChip: { paddingHorizontal: 12, paddingVertical: 6, borderRadius: 16, backgroundColor: CARD_BG, borderWidth: 1, borderColor: CARD_BORDER },
   434|  filterChipActive: { borderColor: GOLD, backgroundColor: GOLD + '15' },
   435|  filterText: { color: '#888', fontSize: 12, fontWeight: '600' as const },
   436|  filterTextActive: { color: GOLD },
   437|  agentsContainer: { padding: 12, gap: 12 },
   438|  agentCard: { backgroundColor: CARD_BG, borderRadius: 12, padding: 16, borderWidth: 1, borderColor: CARD_BORDER },
   439|  agentCardHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 },
   440|  agentNumberBadge: { backgroundColor: GOLD + '20', paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6 },
   441|  agentNumberText: { color: GOLD, fontSize: 11, fontWeight: '700' as const },
   442|  seniorityBadge: { paddingHorizontal: 8, paddingVertical: 4, borderRadius: 6, borderWidth: 1 },
   443|  seniorityText: { fontSize: 11, fontWeight: '700' as const },
   444|  agentName: { color: '#FFF', fontSize: 16, fontWeight: '700' as const, marginBottom: 2 },
   445|  agentRole: { color: '#AAA', fontSize: 13, marginBottom: 8 },
   446|  scoreBar: { height: 6, backgroundColor: '#333', borderRadius: 3, marginBottom: 4 },
   447|  scoreBarFill: { height: 6, borderRadius: 3 },
   448|  scoreText: { color: '#888', fontSize: 11, marginBottom: 6 },
   449|  agentGap: { color: '#999', fontSize: 12, marginBottom: 8, lineHeight: 16 },
   450|  agentMetaRow: { flexDirection: 'row', gap: 12 },
   451|  agentMeta: { color: '#666', fontSize: 11 },
   452|  ledgerToggle: { padding: 16, backgroundColor: CARD_BG, marginHorizontal: 12, borderRadius: 8, borderWidth: 1, borderColor: CARD_BORDER },
   453|  ledgerToggleText: { color: GOLD, fontSize: 16, fontWeight: '700' as const },
   454|  ledgerContainer: { marginHorizontal: 12, marginBottom: 12, backgroundColor: CARD_BG, borderRadius: 12, padding: 12, borderWidth: 1, borderColor: CARD_BORDER },
